          p: { type: "expression", value: "i===0?10:i===1?20:i===2?25:i===3?50:i===4?10:i===5?20:i===6?25:i===7?50:i===8?10:i===9?20:i===10?25:i===11?50:i===12?10:i===13?20:i===14?25:50" },
          action: { type: "expression", value: 'i <= 7 ? "снизилась" : "выросла"' },
