          { pattern: '(a * c) + "/" + (b + d)', feedback: "Числители перемножены верно, но знаменатели тоже нужно перемножить: {b} × {d} = {den}." },
          { pattern: 'a + "/" + (b * d)', feedback: "Не забудь умножить оба числителя: {a} × {c} = {num}." }
