function createAdaptiveState(initialDifficulty = 1) {
  return {
    currentDifficulty: Math.max(1, Math.min(4, initialDifficulty)),
    consecutiveCorrect: 0,
    consecutiveWrong: 0,
    recentAnswers: []
  };
}
function updateAdaptiveState(state, isCorrect) {
  const newRecentAnswers = [...state.recentAnswers, isCorrect].slice(-10);
  let newConsecutiveCorrect = state.consecutiveCorrect;
  let newConsecutiveWrong = state.consecutiveWrong;
  if (isCorrect) {
    newConsecutiveCorrect++;
    newConsecutiveWrong = 0;
  } else {
    newConsecutiveWrong++;
    newConsecutiveCorrect = 0;
  }
  let accuracy = 0;
  if (newRecentAnswers.length >= 5) {
    const correctCount = newRecentAnswers.filter((a) => a).length;
    accuracy = correctCount / newRecentAnswers.length;
  }
  let newDifficulty = state.currentDifficulty;
  if (newConsecutiveCorrect >= 3) {
    newDifficulty = Math.min(4, newDifficulty + 1);
    newConsecutiveCorrect = 0;
  }
  if (newConsecutiveWrong >= 3) {
    newDifficulty = Math.max(1, newDifficulty - 1);
    newConsecutiveWrong = 0;
  }
  if (newRecentAnswers.length >= 10 && accuracy < 0.4) {
    newDifficulty = Math.max(1, newDifficulty - 1);
  }
  if (newRecentAnswers.length >= 10 && accuracy > 0.8) {
    newDifficulty = Math.min(4, newDifficulty + 1);
  }
  return {
    currentDifficulty: newDifficulty,
    consecutiveCorrect: newConsecutiveCorrect,
    consecutiveWrong: newConsecutiveWrong,
    recentAnswers: newRecentAnswers
  };
}
function getDifficultyLabel(difficulty) {
  switch (difficulty) {
    case 1:
      return "Легко";
    case 2:
      return "Средне";
    case 3:
      return "Сложно";
    case 4:
      return "Олимпиадное";
  }
}
const DIFFICULTY_WEIGHTS = {
  1: 0.4,
  2: 0.35,
  3: 0.2,
  4: 0.05
};
function weightedRandom(items) {
  const weights = items.map((item) => DIFFICULTY_WEIGHTS[item.difficulty] ?? 0.1);
  const total = weights.reduce((sum, w) => sum + w, 0);
  let rand = Math.random() * total;
  for (let i = 0; i < items.length; i++) {
    rand -= weights[i];
    if (rand <= 0) return items[i];
  }
  return items[items.length - 1];
}
function createProblemSession(topic, difficulty = 1) {
  return {
    topic,
    currentDifficulty: Math.max(1, Math.min(4, difficulty)),
    streak: 0,
    recentTemplateIds: [],
    accuracy: 0
  };
}
function getDifficultyForTemplate(template, targetDifficulty) {
  if (template.difficulties[targetDifficulty]) {
    return targetDifficulty;
  }
  for (let d = targetDifficulty - 1; d >= 1; d--) {
    if (template.difficulties[d]) {
      return d;
    }
  }
  for (let d = targetDifficulty + 1; d <= 4; d++) {
    if (template.difficulties[d]) {
      return d;
    }
  }
  return null;
}
function selectTemplate(templates2, session) {
  if (templates2.length === 0) {
    return null;
  }
  let candidates = templates2.filter((t) => t.topic === session.topic);
  if (candidates.length === 0) {
    return null;
  }
  const notRecent = candidates.filter((t) => !session.recentTemplateIds.includes(t.id));
  if (notRecent.length > 0) {
    candidates = notRecent;
  }
  const withDifficulty = candidates.map((t) => ({
    template: t,
    difficulty: getDifficultyForTemplate(t, session.currentDifficulty)
  })).filter((item) => item.difficulty !== null);
  if (withDifficulty.length === 0) {
    return null;
  }
  const sortedByCloseness = withDifficulty.sort((a, b) => {
    const diffA = Math.abs(a.difficulty - session.currentDifficulty);
    const diffB = Math.abs(b.difficulty - session.currentDifficulty);
    return diffA - diffB;
  });
  const closestDiff = Math.abs(sortedByCloseness[0].difficulty - session.currentDifficulty);
  const closestMatches = sortedByCloseness.filter(
    (item) => Math.abs(item.difficulty - session.currentDifficulty) === closestDiff
  );
  const selected = weightedRandom(closestMatches);
  return selected.template;
}
function updateSessionAfterSelection(session, templateId) {
  const newRecentIds = [...session.recentTemplateIds, templateId].slice(-5);
  return {
    ...session,
    recentTemplateIds: newRecentIds
  };
}
